def find_prime_factors(number):
    factors = []
    d = 2
    temp_number = number

    while d * d <= temp_number:
        while temp_number % d == 0:
            factors.append(d)
            temp_number //= d
        d += 1

    if temp_number > 1:
        factors.append(temp_number)

    return factors
